function TuIALogo({ size = 36 }) {
  return (
    <svg width={size} height={size} viewBox="0 0 60 55" fill="none">
      <defs>
        <linearGradient id="tg" x1="30" y1="5" x2="30" y2="52" gradientUnits="userSpaceOnUse">
          <stop offset="0%" stopColor="#1A2FA0"/>
          <stop offset="60%" stopColor="#2B50CC"/>
          <stop offset="100%" stopColor="#6688DD"/>
        </linearGradient>
      </defs>
      <path d="M8 52 L30 8 L52 52" stroke="url(#tg)" strokeWidth="11"
        strokeLinecap="round" strokeLinejoin="round" fill="none"/>
    </svg>
  );
}

