function TuIABtn({ onTap, onLongStart, onLongEnd, size=56 }) {
  const timerRef = useRef(null);
  const [down, setDown] = useState(false);
  const didLong = useRef(false);
  const ps = (e) => { e.preventDefault(); didLong.current=false; setDown(true); timerRef.current=setTimeout(()=>{didLong.current=true;onLongStart();},1500); };
  const pe = () => { setDown(false); if(timerRef.current){clearTimeout(timerRef.current);timerRef.current=null;} if(didLong.current){onLongEnd();didLong.current=false;}else onTap(); };
  return (
    <div onMouseDown={ps} onMouseUp={pe} onMouseLeave={pe} onTouchStart={ps} onTouchEnd={pe}
      style={{ width:size,height:size,borderRadius:size*0.28,background:"rgba(255,255,255,0.12)",
        backdropFilter:"blur(12px)",border:"1.5px solid rgba(255,255,255,0.22)",
        boxShadow:"0 4px 20px rgba(0,0,0,0.35)",display:"flex",alignItems:"center",justifyContent:"center",
        cursor:"pointer",userSelect:"none",transform:down?"scale(0.9)":"scale(1)",
        transition:"transform 0.1s",position:"relative",overflow:"hidden" }}>
      <div style={{ position:"absolute",top:0,left:0,right:0,height:"42%",background:"linear-gradient(180deg,rgba(255,255,255,0.16) 0%,transparent 100%)",pointerEvents:"none" }}/>
      <TuIALogo size={size*0.62}/>
    </div>
  );
}

